```js
// sumArr.js
/**
 * Returns the sum of all numeric values in the given array.
 * Non‑numeric entries are ignored.
 *
 * @param {Array<number>} arr - An array of numbers (or mixed values).
 * @returns {number} The total sum.
 */
function sumArr(arr) {
  if (!Array.isArray(arr)) {
    throw new TypeError('Expected an array');
  }

  return arr.reduce((total, val) => {
    // Only add numbers (NaN, undefined, etc. are skipped)
    return typeof val === 'number' && !Number.isNaN(val)
      ? total + val
      : total;
  }, 0);
}

// Export the function for use in other files
module.exports = sumArr;
```

**Usage example**

```js
// index.js
const sumArr = require('./sumArr');

const numbers = [1, 2, 3, 4, 5];
console.log(sumArr(numbers)); // → 15

// Mixed array – non‑numbers are ignored
console.log(sumArr([10, 'a', null, 5])); // → 15
```

The function validates that the input is an array, then uses `Array.prototype.reduce` to accumulate the sum, safely ignoring any non‑numeric values. Feel free to adjust the validation or handling of non‑numeric items to suit your needs.

