def fizzbuzz(n):
    """
    Return the FizzBuzz sequence for numbers 1 through n inclusive.
    Each element is a string: "FizzBuzz" for multiples of 15,
    "Fizz" for multiples of 3, "Buzz" for multiples of 5,
    otherwise the number itself.
    """
    result = []
    for i in range(1, n + 1):
        if i % 15 == 0:
            result.append("FizzBuzz")
        elif i % 3 == 0:
            result.append("Fizz")
        elif i % 5 == 0:
            result.append("Buzz")
        else:
            result.append(str(i))
    return result
